import shutil
import errno


class Logger(object):
    def __init__(self, filename='default', level=10):
        self._filename = filename
        self._level = level

    @staticmethod
    def _get_time():
        return str(datetime.datetime.now())

    def log(self, level, message):

        if int(level) >= self._level:
            with open(self._filename + '.log', 'a') as file:
                file.write(str(Logger._get_time() + ' ' + message))


class RotatingFileHandler(object):
    def __init__(self, filename='default'):
        self._filename = filename

    @staticmethod
    def _get_time():
        return str(datetime.datetime.now())

    def rotate(self):

        try:
            shutil.copyfile(self._filename + '.log',
                            self._filename + '_' + Logger._get_time() + '.log')

            os.remove(self._filename + '.log')

        except IOError as e:
            if e.errno != errno.ENOENT:
                raise


class FilePermissionsHandler(object):
    def __init__(self, filename='default'):
        self._filename = filename

    @staticmethod
    def _get_time():
        return str(datetime.datetime.now())

    def set_permissions(self):

        try:
            os.chmod(self._filename + '.log', 0o755)

        except IOError as e:
            if e.errno != errno.ENOENT:
                raise


class LogManager(object):
    def __init__(self, filename='default'):
        self._filename = filename

